revision.text:
body.skin-minerva .navbar {
	display: inline;
	font-size: 88%;
	font-weight: normal;
}
.navbar ul {
	display: inline;
	white-space: nowrap;
}
.navbar li {
	word-spacing: -0.125em;
}
.navbar.mini li span {
	font-variant: small-caps;
}
/* Navbar styling when nested in infobox and navbox */
.navbox .navbar,
.infobox .navbar {
	font-size: 100%;
}
.navbox .navbar {
	display: block;
}
.navbox-title .navbar {
	/* @noflip */
	float: left;
	/* @noflip */
	text-align: left;
	/* @noflip */
	margin-right: 0.5em;
	width: 6em;
}

body.skin-minerva .navbar {
	display: inline;
	font-size: 88%;
	font-weight: normal;
}
body.skin-minerva .navbar ul {
	display: inline;
	white-space: nowrap;
}
body.skin-minerva .navbar li {
	word-spacing: -0.125em;
}
.body.skin-minerva navbar.mini li span {
	font-variant: small-caps;
}
/* Navbar styling when nested in infobox and navbox */
body.skin-minerva .navbox .navbar,
body.skin-minerva .infobox .navbar {
	font-size: 100%;
}
body.skin-minerva .navbox .navbar {
	display: block;
}
body.skin-minerva .navbox-title .navbar {
	/* @noflip */
	float: left;
	/* @noflip */
	text-align: left;
	/* @noflip */
	margin-right: 0.5em;
	width: 6em;
}

/* CSS below is common */
.navbar {
	display: inline;
	font-size: 88%;
	font-weight: normal;
}

.navbar ul {
	display: inline-block;
	white-space: nowrap;
}

body.skin-Minerva .navbar ul {
	display: inline; /* why does mobile differ here? */
}

.navbar li {
	word-spacing: -0.125em;
}
/*
Space reserved for remaining common fixes.




*/

/* Navbar styling when nested in infobox and navbox */
/* Should consider having a separate TemplateStyles for those specific places
using an infobox/navbox and a navbar */
.infobox .navbar {
	font-size: 100%;
}

.navbox .navbar {
	display: block;
	font-size: 100%;
}

.navbox-title .navbar {
	/* @noflip */
	float: left;
	/* @noflip */
	text-align: left;
	/* @noflip */
	margin-right: 0.5em;
}

body.skin-Minerva .navbox-title .navbar {
	width: 6em; /* Why does mobile set this width? */
}

/* CSS below is from Common.css */
.mw-body-content .navbar ul {
	line-height: inherit; /* Why is this missing in Minerva? */
}
.navbar.mini li abbr[title] {
	font-variant: small-caps;
	border-bottom: none;
	text-decoration: none;
	cursor: inherit;
}

/* CSS below is from Mobile.css */
.navbar.mini li span {
	font-variant: small-caps; /* This just looks like it missed the update to abbr */
}

/* CSS below is common */
.navbar {
	display: inline;
	font-size: 88%;
	font-weight: normal;
}

.navbar ul {
	display: inline-block;
	white-space: nowrap;
}

body.skin-Minerva .navbar ul {
	display: inline; /* why does mobile differ here? */
}

.navbar li {
	word-spacing: -0.125em;
}
/*
Space reserved for remaining common fixes.




*/

/* Navbar styling when nested in infobox and navbox */
/* Should consider having a separate TemplateStyles for those specific places
